SELECT 
FROM expense_record WHERE register_id = #{registerId}
ORDER BY create_time DESC

SELECT 
FROM expense_record WHERE patient_id = #{patientId}
ORDER BY create_time DESC

SELECT 
FROM expense_record WHERE status = #{status}
ORDER BY create_time DESC

SELECT 
FROM expense_record
WHERE register_id = #{registerId}
  AND source_id = #{sourceId}
  AND item_code = #{itemCode}
ORDER BY id DESC
LIMIT 1

SELECT 
FROM expense_record

    AND patient_id = #{patientId}
    AND register_id = #{registerId}
    AND status = #{status}
    AND pay_time >= #{startTime}
    AND pay_time < #{endTime}

ORDER BY create_time DESC

SELECT 
FROM expense_record

    AND patient_id = #{patientId}

        AND (
            patient_name ILIKE CONCAT('%', #{keyword}, '%')
            OR CAST(register_id AS TEXT) LIKE CONCAT('%', #{keyword}, '%')
        )

    AND create_time >= #{startTime}
    AND create_time < #{endTime}

ORDER BY create_time DESC

